var e=JSON.parse(`[{"id":"L14_1","type":"dialog","speaker":"SQUADMEMBER_NPC_NULL_NULL","text":{"KOREA":"훈련 종료!","JPN":"訓練終了！","ENG":"Training completed!","TWN":"訓練結束！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SQUADMEMBER_NPC_NULL_NULL","text":{"KOREA":"어, 엄청납니다. 소령님께선 모의훈련 최단시간을 고작 일주일 사이에 거의 절반이나 단축하시다니.","JPN":"す、すごい。少佐は、模擬訓練の最短時間をたった一週間の間にほぼ半分にも短縮されましたか。","ENG":"T-that's incredible. Major Wong managed to break the record for the simulation training by half in just a week.","TWN":"太，太誇張了。少校居然把模擬訓練的最快記錄縮短了將近半個禮拜。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"애초에 이건 분대단위로 진행하는 훈련이야. 소령님은 그걸 혼자서 해내고 계신 거라고.","JPN":"そもそもこれは分隊単位で行う訓練だ。少佐はそれを一人でこなしているんだよ。","ENG":"This training is designed for squad level units in the first place. Major Wong did that all by himself.","TWN":"這訓練一開始是以班為作戰單位進行的啊，結果少校獨自一人就完成了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SQUADMEMBER_NPC_NULL_NULL","text":{"KOREA":"현장 전투원이 아니신데도 저런 성과를 낼 수 있다니. 역시 카운터는 달라도 뭔가 다르군요.","JPN":"現場の戦闘員でもないのに、あんな成果を出すなんて。やっぱりカウンターはなんか違いますね。","ENG":"And he's not even a combat operative. I guess Counters are cut from a different cloth after all.","TWN":"明明不是現場參戰人員卻能有那種成績，果然制裁者就是不一樣啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"아니. 자기가 카운터라고 떠벌려대는 용병들을 여럿 만나봤지만, 전부 거들먹거리기나 좋아하고 몸이 좀 튼튼한 정도일 뿐이었어.","JPN":"いや、カウンターだと自称する傭兵たちにたくさん会ってきたが、\\nどいつもこいつも調子に乗るだけで、体が丈夫なこと以外は何の取り柄もなかったんだ。","ENG":"No, it's not just that. I've met plenty of mercs who brag about their Counter abilities, but it was all talk. Sure, they're a bit sturdier than normal folks, but that was it.","TWN":"不，我見過很多洋洋得意，自稱是制裁者的傭兵，但他們大多就只是壯了一些罷了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"하지만 소령님은 근본부터가 달라. 카운터들 중에서도 뛰어난 엘리트니까.","JPN":"しかし、少佐は彼らと根本的に違う。カウンターたちの中でも優れたエリートなんだ。","ENG":"There's something fundamentally different about Major Wong. After all, he stands out even among the Counters.","TWN":"但少校完全不一樣，畢竟少校在制裁者裡也是精英中的精英。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다들 오늘도 고생 많았습니다. 그만 정리하고 막사로 철수하도록 하죠.","JPN":"みんな、今日もお疲れ様でした。そろそろ片付けて兵舎に戻りましょう。","ENG":"Good work today, everyone. Let's wrap up and head back to the barracks.","TWN":"大家辛苦了。今天就到此為止，大家都回營地吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAPTAIN_TOY_NULL_NULL","text":{"KOREA":"옙! 소령님!","JPN":"はっ！　少佐！","ENG":"Roger that! Sir!","TWN":"是！少校!"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자, 자 카일 웡 소령님. 이쪽을 봐 주세요.","JPN":"さあ、さあ、カイル・ウォン少佐。こっちを見てください。","ENG":"Alright, Major Kyle Wong. Please take a look at me.","TWN":"來吧，凱爾少校。請看這邊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자...... 짜잔! 여기선 아무 일도 없었습니다. 그렇지 않나요?","JPN":"……ジャジャーン！　こちらでは何事もなかったです。そうでしょう？","ENG":"Now... Tah-dah! Nothing happened here, did it?","TWN":"來……鏘鏘！這裡什麼事都沒有發生。不是嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이상해.","JPN":"おかしい。","ENG":"Something is off.","TWN":"奇怪。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무리 뒤져봐도 분명 그날은 기지에 불법침입의 흔적이 없었는데.","JPN":"いくら調べてみてもその日は基地に不法侵入した痕跡がなかったはずだ。","ENG":"There were no signs of forcible entry into the base that day no matter how hard I looked.","TWN":"明明那天基地被非法入侵了，可是不管怎麼找都找不到痕跡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 어렴풋한 기억은 대체 뭐지? 내가 꿈이라도 꾼 건가?","JPN":"このぼんやりとした記憶はいったいなんだ？　僕は夢でも見たのか？","ENG":"So what's this faint memory I have? Did I dream it or something?","TWN":"這段模糊的記憶到底是什麼？難道我是在做夢嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하하하!","JPN":"はははは！","ENG":"Hah hah hah!","TWN":"哈哈哈哈！"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"너랑 똑같이 생긴 여자라니. 여동생이라도 갖고 싶었던 거냐? 안 어울리게.","JPN":"お前にそっくりの女だと？　妹でも欲しかったのか？　お前らしくねぇな。","ENG":"A girl who looks just like you? Were you hoping for a younger sister or something? It's not like you.","TWN":"居然說有和你長得一模一樣的女人。你就那麼想要個妹妹嗎？這可不像你啊。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님. 누차 말씀 드리지만 이건 꿈 얘기가 아닙니다.","JPN":"大佐。何度も言いましたが、これは夢ではありません。","ENG":"Colonel. As I've said repeatedly, this was not a dream.","TWN":"上校，我說過好幾次了，這絕對不是夢。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래, 그래.","JPN":"わかった、わかったから。","ENG":"Sure, sure.","TWN":"好，好。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"다른 사람이면 몰라도 일분 일초를 치밀하게 계획하는 네가 몇 시간씩이나 예정과 어긋나는 행동을 했다는 건 확실히 이상하긴 해.","JPN":"他の人でもない、秒単位で緻密に計画するお前が、何時間も予定外の行動を取ったことは確かにおかしい。","ENG":"I guess it really is weird that you of all people went off plan for hours. I mean, you always plan and execute everything down to the minute or even to the second.","TWN":"別人我是不知道，但你的計畫可是周密到以秒來計算的，你這樣的人竟然會有好幾小時做出和計畫相左的行動，這確實很異常。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐, 사실 그렇잖아도 연구기지에 4종이 휩쓸고 간 뒤로 부대 내에 별 희한한 목격담이 많긴 하더군.","JPN":"まぁ、実を言うと、第4種が研究基地を荒らし回った後から部隊内で不思議な目撃談が増えてきたようなんだ。","ENG":"In fact, there has been a lot of uncanny sightings on base after we had the Category 4 sweep across the research area.","TWN":"其實我們將研究基地裡的4級侵蝕體都打倒後，部隊裡的確有很多人目擊到奇怪現象。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"부대가 소란스러워질 것 같아서 입단속을 시켜두긴 했는데......","JPN":"部隊が騒がしくなると思って口止めしておいたんだけど……","ENG":"I had everyone zip their lips in case it causes a commotion on base...","TWN":"雖然為防止部隊出現騷亂所以進行了封口處理……"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"왠 칼잡이 두 명이 무협영화를 찍었다는 얘기도 있고, 네가 두 사람으로 나뉘어져서 옥신각신 말다툼을 하더라는 공통적인 증언도 있었지.","JPN":"なんか、二人の剣士が武術映画を撮影したという話もあれば、お前が二人に分かれて口喧嘩したという共通する証言もあった。","ENG":"Some say these two sword wielders shot a kung fu movie. There were also multiple accounts of seeing two copies of you having an argument.","TWN":"但有很多人提供了相似的證言，說看到兩個劍客在拍武俠電影，也有人說你分裂成了兩個人互相爭吵。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"문제는 증언만 있을 뿐, 백업 데이터조차 날아가버려서 증거가 없다는 거지만.","JPN":"問題は、証言だけあってバックアップデータすら消えてしまって証拠がない。","ENG":"The thing is, we only have verbal testimonies to go on. With the back up data gone, there's no hard evidence.","TWN":"問題就是，只有證言沒有證據，甚至連備份的資料也都不翼而飛了。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......그 칼잡이.","JPN":"……あの剣士。","ENG":"That swordsman...","TWN":"……那個劍客。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지난 리플레이서 작전에서 봤던 코핀 컴퍼니의 직원과 동일인물이었어요.","JPN":"先日のリプレイサー作戦で見たコフィンカンパニーの職員と同一人物でした。","ENG":"It was the same person as the Coffin Company employee we saw at the Replacer operation.","TWN":"和上次在克隆集團作戰時看到的科芬公司職員是同一人。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그때 거둬들인 성과도 그렇고, 그들은 평범한 3류 태스크포스가 아닙니다.","JPN":"あの時あげた成果を見ても、彼らはそこらの三流タスクフォースではありません。","ENG":"They proved to be quite capable back then as well... They are not your average third-rate TASKFORCE.","TWN":"那時取得的成果也是，他們絕不是一般的3流特遣勢力。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래? 그 녀석들이라고......?","JPN":"そうか？　あいつらが……？","ENG":"Really? It was those guys, huh?","TWN":"嗯？你是說他們……？"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇습니다..","JPN":"そうです｡","ENG":"Affirmative.","TWN":"是的。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 사건에서도 결정적인 역할을 했고 악의가 느껴지지는 않습니다만......","JPN":"リプレイサー事件でも決定的な役割を果たし、悪意は感じられませんが……","ENG":"Although they were instrumental in resolving the Replacer case and I do not sense any malice in their intent...","TWN":"他們在克隆集團事件中也起了決定性作用，雖然不覺得他們有惡意……"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......그렇다고 앞으로도 지금처럼 끌려 다닐 수는 없겠지.","JPN":"……だとしても、これからも今まで通りに振り回されるわけにはいかないな。","ENG":"But we can't let them keep dragging us around either.","TWN":"……但也不能一直像現在這樣被他們牽著鼻子走。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님 말씀에 동의합니다.","JPN":"僕も同感です。","ENG":"I fully concur with you, sir.","TWN":"我同意上校的話。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그럼 사령관님께는 어떻게 보고할 거야?","JPN":"それで、司令官にどう報告するつもりだ？","ENG":"Then how are you going to brief the CG?","TWN":"那你要怎麼向司令官報告？"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중대 사안이긴 하지만...... 아직은 그럴만한 단계가 아닙니다.","JPN":"重大事案ではありますが……まだそういう段階ではありません。","ENG":"While it is an issue of utmost importance, it's still too soon for that.","TWN":"雖然這次事件很重大……但我認為還沒到時候。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"좀 더 자세한 내막을 파악할 필요가 있고, 지난 번과 같은 수법에 당해서도 안 되니까요.","JPN":"もう少し詳しい内容を把握する必要がありますし、先日と同じ手法にやられてもいけませんので。","ENG":"We need to look into the matter further, and we mustn't fall for the same trick again.","TWN":"我們需要掌握更詳細的內幕情報，不能被同樣的手法欺騙第二次。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......그래. 무슨 뜻인진 알겠어.","JPN":"……ああ。言ってることはわかった。","ENG":"Yeah. I see what you mean.","TWN":"……是嗎。我知道你的意思了。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이 문제를 해결하기 위해선 먼저 스스로가 강해져야 한다는 거지?","JPN":"この問題を解決するためにはまず、自ら強くなる必要があるってことだな？","ENG":"So you're saying you need to get stronger in order to solve this case, huh?","TWN":"為了能夠順利解決問題，首先要讓自己變強是吧？"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"난 네가 자존심만 센 완벽주의자라고 생각했는데, 다시 봐야겠는걸?","JPN":"俺は、お前がプライドだけ高い完璧主義者だと思っていたが、少しは見直さないとな。","ENG":"I thought you were just a headstrong perfectionist. I guess I was wrong about you.","TWN":"我還以為你是個只有自尊心的完美主義者，看來我得對你刮目相看了。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 사건 이후, 저희는 발전의 필요성을 몸소 체감했습니다.","JPN":"リプレイサー事件以来、僕たちは成長の必要性を実感しました。","ENG":"I fully realized the need for further progress after the Replacer incident.","TWN":"克隆集團事件後，我親身感受到成長的重要性。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"정신론의 교정이나 체력훈련 같은 걸로는 극복해낼 수 없다는 것도 깨달았죠.","JPN":"性根の叩き直しや体力訓練のようなものでは克服できないことも気づきました。","ENG":"I also realized it was not merely a matter of mental aptitude or physical fitness.","TWN":"也明白了光靠矯正精神和鍛煉體力是無法克服那些困難的。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제게도 좀 더 과감한 변화가 필요합니다.","JPN":"僕にもより大胆な変化が必要です。","ENG":"I too must undergo more daring changes.","TWN":"我需要更大的改變。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 그런 극단적인 변화를 이뤄내기 위해선 대령님의 도움이 필요하다고 생각했습니다.","JPN":"そして、その極端な変化を成し遂げるためには大佐の支えが必要だと思っています。","ENG":"In order to achieve such extreme changes, I concluded that I would need your help, sir.","TWN":"並且，我認為要想獲得徹底的改變，我需要上校的幫助。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니, 부디 협조를 부탁드립니다. 제이크 워커 대령님.","JPN":"なので、どうかご協力お願いします。ジェイク・ウォーカー大佐。","ENG":"So I would most appreciate your cooperation. Colonel Jake Walker, sir.","TWN":"所以，請您務必幫助我。傑克·沃克上校。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"너의 그 딱딱하고 멋스럽지 않은 말투는 여전하다만......","JPN":"お前のその堅苦しくてダサい喋り方は相変わらずだが……","ENG":"Well, you sound just as robotic and boring as ever...","TWN":"你的語氣還是那麼死板的，真是一點都不帥氣啊……"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이젠 확실히 이전에는 없던 뜨거운 열정이 느껴지는걸?","JPN":"確かに、この前まではなかった熱い情熱を感じるぜ。","ENG":"But I can sense a burning passion that wasn't there before.","TWN":"不過我能感受到，現在的你比以往任何時候都要熱血喔？"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋아. 내일부터 특훈 시작이다.","JPN":"よし。明日から特訓だ。","ENG":"Very well. Your special training begins tomorrow.","TWN":"好的，明天開始特訓。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"힘들다고 적당히 넘어가지 않을 테니까, 각오하라고 카일.","JPN":"大変になると思うが、適当にやるつもりはないから覚悟しろよ、カイル。","ENG":"I'm not going to go easy on you, so brace yourself, Kyle.","TWN":"就算你喊累我也不會輕易放過你的，做好覺悟吧，凱爾。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"좋습니다. 얼마든지요.","JPN":"いいでしょう。望むところです。","ENG":"Very good. Gladly.","TWN":"是的，越辛苦越好。"},"stage":{"bg":"OFFICE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};